questionvariables.text:
/* Random set selection: 1..4 */
set: rand(4)+1;

/* Frequency in Hz */
f_Hz: if set=1 then 1e3 else if set=2 then 100e6 else if set=3 then 10e6 else 1e9;

/* Line length in metres */
l_m: if set=1 then 0.05 else if set=2 then 0.30 else if set=3 then 0.05 else 0.02;

/* Phase velocity in m/s */
vp: if set=1 then 2e8 else if set=2 then 3e8 else if set=3 then 2e8 else 2e8;

/* Display-friendly strings */
f_disp: if set=1 then "1 kHz" else if set=2 then "100 MHz" else if set=3 then "10 MHz" else "1 GHz";
l_cm: float(l_m * 100);
vp_disp: if set=1 then "2" else if set=2 then "3" else if set=3 then "2" else "2";

/* --- Teacher answers --- */

/* Part (a): wavelength in metres */
ta1: float(vp / f_Hz);

/* Part (b): electrical length ratio */
ta2: float(l_m / ta1);

/* Part (e): l/lambda when frequency is multiplied by 100 */
ratio_high: float(ta2 * 100);

/* Logical flags for threshold comparison */
is_distributed: is(ta2 >= 0.01);
is_distributed_high: is(ratio_high >= 0.01);

/* Part (c): dropdown Yes/No — Is l/lambda >= 0.01? */
ta3: [[1, is(ta2 >= 0.01), "Yes"], [2, is(ta2 < 0.01), "No"]];
ta3_correct: if is(ta2 >= 0.01) then 1 else 2;

/* Part (d): dropdown Distributed/Lumped */
ta4: [[1, is(ta2 >= 0.01), "Distributed"], [2, is(ta2 < 0.01), "Lumped"]];
ta4_correct: if is(ta2 >= 0.01) then 1 else 2;

/* Part (e) teacher answer */
ta5: float(ratio_high);

/* Part (f): dropdown Distributed/Lumped at higher freq */
ta6: [[1, is(ratio_high >= 0.01), "Distributed"], [2, is(ratio_high < 0.01), "Lumped"]];
ta6_correct: if is(ratio_high >= 0.01) then 1 else 2;

/* Part (g): radio — 4 options, option 1 always correct */
ta7: [[1,true,"At higher frequencies, the wavelength shrinks and becomes comparable to the line length, so wave propagation effects matter"],[2,false,"Higher frequencies increase the resistance of the line, requiring distributed analysis"],[3,false,"The speed of light decreases at higher frequencies"],[4,false,"Higher frequencies make the line physically longer"]];
ta7_correct: 1;

/* Part (h): minimum frequency for distributed model */
ta8: float(0.01 * vp / l_m);

/* Part (i): sensitivity — if vp is 20% lower */
ta8_low: float(0.8 * ta8);
ta8_disp: if is(ta8 >= 1e9) then sconcat(string(float(ta8/1e9)), " GHz")
          else if is(ta8 >= 1e6) then sconcat(string(float(ta8/1e6)), " MHz")
          else if is(ta8 >= 1e3) then sconcat(string(float(ta8/1e3)), " kHz")
          else sconcat(string(float(ta8)), " Hz");

/* Radio MCQ: option 1 is always correct — lower vp → lower f_min → conservative */
ta9: [[1,true,"The distributed model becomes necessary at a lower frequency than calculated — my design is conservative (safe)"],[2,false,"The distributed model becomes necessary at a higher frequency — my design may be optimistic (risky)"],[3,false,"The phase velocity has no effect on the model choice"],[4,false,"I must switch to the distributed model regardless of frequency"]];
ta9_correct: 1;
